const langResult = $('LangGraph Analyze').first().json;
const job_id = $('Insert row').first().json.job_id;

let imageAnalysis = '';
let imageUrl = '';

try {
  const img = $('Image Analyzer').first().json;
  if (img && img.room_type) {
    imageAnalysis = 'Room: ' + img.room_type + ' | Condition: ' + img.condition_score + '/1.0 | Confidence: ' + Math.round(img.confidence * 100) + '%';
  }
} catch (e) {}

try {
  // Only build URL if Image Analyzer ran (S3 upload succeeded)
  const imgResult = $('Image Analyzer').first().json;
  const fileName = $('User Submit').first().binary?.file?.fileName || '';
  if (imgResult && fileName) {
    imageUrl = 'https://fp-property-images.s3.amazonaws.com/' + job_id + '/' + fileName;
  }
} catch (e) {}

let result;
if (langResult.status === 'incomplete') {
  result = langResult.clarification_message || 'Submission incomplete — missing fields: ' + (langResult.missing_fields || []).join(', ');
} else {
  const a = langResult.analysis || {};
  result = [
    '**Embassy Recommendation:** ' + (a.recommendation || 'N/A'),
    '',
    '**Market Context:** ' + (a.market_context || ''),
    '',
    '**Property Assessment:** ' + (a.property_assessment || ''),
    '',
    '**Pricing Opinion:** ' + (a.pricing_opinion || ''),
    '',
    '**Expected Timeline:** ' + (a.expected_timeline || ''),
  ].join('\n');
  if (imageAnalysis) {
    result += '\n\n**Image Analysis:** ' + imageAnalysis;
  }
}

return [{ json: {
  job_id,
  result,
  status: langResult.status,
  intent: langResult.intent,
  confidence: langResult.confidence || 0,
  recommendation: (langResult.analysis || {}).recommendation || 'PASS',
  image_urls: imageUrl ? JSON.stringify([imageUrl]) : '',
  image_analysis: imageAnalysis,
} }];

const items = $input.all();
const webhookBinary = $('User Submit').first().binary || {};
return items.map(item => ({
  json: item.json,
  binary: webhookBinary,
}));
